161→export function ClipboardHistoryView() {
162→  const nav = useNavigation();
163→  const [entries, setEntries] = useState<ClipboardEntry[]>(
164→    MOCK_CLIPBOARD_ENTRIES,
165→  );
166→  const [query, setQuery] = useState('');
167→  const [filterValue, setFilterValue] = useState('all');
168→  const [selectedIndex, setSelectedIndex] = useState(0);
169→  const [actionsOpen, setActionsOpen] = useState(false);
170→  const { items: hudItems, show: showHUD } = useHUD();
171→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
172→  const now = useMemo(() => new Date(), []);
173→
174→  const filtered = useMemo(() => {
175→    let items = entries;
176→    if (filterValue !== 'all') {
177→      items = items.filter(e => e.contentType === filterValue);
178→    }
179→    if (query) {
180→      const lower = query.toLowerCase();
181→      items = items.filter(
182→        e =>
183→          e.content.toLowerCase().includes(lower) ||
184→          e.sourceApp.toLowerCase().includes(lower),
185→      );
186→    }
187→    return items;
188→  }, [
189→    entries,
190→    query,
191→    filterValue,
192→  ]);
193→
194→  const pinnedItems = useMemo(() => filtered.filter(e => e.pinned), [filtered]);
195→  const recentItems = useMemo(
196→    () => filtered.filter(e => !e.pinned),
197→    [filtered],
198→  );
199→  const totalItemCount = filtered.length;
200→
201→  const flatItems = useMemo(
202→    () => [
203→      ...pinnedItems,
204→      ...recentItems,
205→    ],
206→    [
207→      pinnedItems,
208→      recentItems,
209→    ],
210→  );
211→
212→  useEffect(() => {
213→    if (selectedIndex >= totalItemCount && totalItemCount > 0) {
214→      setSelectedIndex(totalItemCount - 1);
215→    } else if (totalItemCount === 0) {
216→      setSelectedIndex(0);
217→    }
218→  }, [
219→    selectedIndex,
220→    totalItemCount,
221→  ]);
222→
223→  const selectedEntry = flatItems[selectedIndex];
224→
225→  const handleQueryChange = useCallback((value: string) => {
226→    setQuery(value);
227→    setSelectedIndex(0);
228→    setActionsOpen(false);
229→  }, []);
230→
231→  const handleFilterChange = useCallback((value: string) => {
232→    setFilterValue(value);
233→    setSelectedIndex(0);
234→  }, []);
235→
236→  const handleActiveIndexChange = useCallback((index: number) => {
237→    setSelectedIndex(index);
238→    setActionsOpen(false);
239→  }, []);
240→
241→  const handleCopy = useCallback(() => {
242→    if (!selectedEntry) return;
243→    setActionsOpen(false);
244→    showHUD({
245→      icon: <ClipboardHUDIcon />,
246→      title: 'Copied to Clipboard',
247→    });
248→  }, [
249→    selectedEntry,
250→    showHUD,
251→  ]);
252→
253→  const handlePaste = useCallback(() => {
254→    if (!selectedEntry) return;
255→    setActionsOpen(false);
256→    showHUD({
257→      icon: <ClipboardHUDIcon />,
