import type { ReactNode } from 'react';
import { DocumentIcon, FolderIcon, GlobeIcon } from '../components/icons';

export type FileType = 'folder' | 'document' | 'code' | 'image' | 'pdf' | 'archive' | 'spreadsheet' | 'presentation';

export interface FileEntry {
  id: string;
  name: string;
  path: string;
  fileType: FileType;
  size: number;
  modifiedAt: Date;
}

function FileCodeIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <rect x="3" y="2" width="14" height="16" rx="2" fill="#5856D6" />
