      <line x1="7.5" y1="14" x2="12.5" y2="14" stroke="#FFFFFF" strokeWidth="1.2" strokeLinecap="round" />
    </svg>
  );
}

function FileFolderIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <defs>
        <linearGradient id="folder-file-bg" x1="0" y1="0" x2="0" y2="1">
