      <line x1="6" y1="10" x2="14" y2="10" stroke="#FFFFFF" strokeWidth="1.2" strokeLinecap="round" />
      <line x1="6" y1="13" x2="11" y2="13" stroke="#FFFFFF" strokeWidth="1.2" strokeLinecap="round" />
    </svg>
  );
}

export function getFileIcon(fileType: FileType): ReactNode {
  switch (fileType) {
    case 'folder':
      return <FileFolderIcon />;
    case 'code':
      return <FileCodeIcon />;
    case 'image':
      return <FileImageIcon />;
    case 'pdf':
      return <FilePdfIcon />;
    case 'archive':
      return <FileArchiveIcon />;
    case 'spreadsheet':
      return <FileSpreadsheetIcon />;
    case 'presentation':
      return <FilePresentationIcon />;
    case 'document':
      return <FileDocumentIcon />;
  }
}

export function FileSearchCommandIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <defs>
        <linearGradient id="filesearch-bg" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#5AC8FA" />
          <stop offset="100%" stopColor="#007AFF" />
        </linearGradient>
      </defs>
      <rect x="1" y="1" width="18" height="18" rx="4" fill="url(#filesearch-bg)" />
      <path
        d="M6 4.5h3.5L12 7v6.5a1 1 0 01-1 1H6a1 1 0 01-1-1V5.5a1 1 0 011-1z"
        stroke="#FFFFFF"
        strokeWidth="1.2"
        strokeLinecap="round"
        strokeLinejoin="round"
        fill="none"
      />
      <path d="M9.5 4.5V7H12" stroke="#FFFFFF" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round" fill="none" />
      <circle cx="12.5" cy="12.5" r="3" stroke="#FFFFFF" strokeWidth="1.2" fill="none" />
      <line x1="14.6" y1="14.6" x2="16" y2="16" stroke="#FFFFFF" strokeWidth="1.2" strokeLinecap="round" />
    </svg>
  );
}

